import express from 'express';
import { getUsers, getUserById, getUserPosts } from './routes/users';
import { getProducts, getProductById } from './routes/products';

const app = express();

app.get('/api/users', getUsers);
app.get('/api/users/:id', getUserById);
app.get('/api/users/:id/posts', getUserPosts);
app.get('/api/products', getProducts);
app.get('/api/products/:id', getProductById);

app.listen(3000, () => console.log('Server on :3000'));

export default app;

import { Request, Response } from 'express';
import { db } from '../db';

export async function getUsers(req: Request, res: Response) {
  const users = await db.query('SELECT id, name, email FROM users');
  res.json(users);
}

export async function getUserById(req: Request, res: Response) {
  const user = await db.query('SELECT * FROM users WHERE id = $1', [req.params.id]);
  if (!user.rows.length) return res.status(404).json({ error: 'Not found' });
  res.json(user.rows[0]);
}

export async function getUserPosts(req: Request, res: Response) {
  const posts = await db.query(
    'SELECT p.* FROM posts p WHERE p.author_id = $1 ORDER BY p.created_at DESC',
    [req.params.id]
  );
  res.json(posts.rows);
}

import { Request, Response } from 'express';
import { db } from '../db';

export async function getProducts(req: Request, res: Response) {
  const products = await db.query(
    'SELECT id, name, price, stock FROM products ORDER BY name'
  );
  res.json(products.rows);
}

export async function getProductById(req: Request, res: Response) {
  const product = await db.query('SELECT * FROM products WHERE id = $1', [req.params.id]);
  if (!product.rows.length) return res.status(404).json({ error: 'Not found' });
  res.json(product.rows[0]);
}

import { Pool } from 'pg';

export const db = new Pool({
  host: process.env.DB_HOST || 'localhost',
  port: Number(process.env.DB_PORT) || 5432,
  database: process.env.DB_NAME || 'myapp',
  user: process.env.DB_USER || 'postgres',
  password: process.env.DB_PASSWORD || 'postgres',
});
